+import rss from "@astrojs/rss";
+import type { APIRoute } from "astro";
+import {
+	getCanonicalUrl,
+	getLinks,
+	getNotes,
+	type Note,
+	siteMeta,
+} from "../../data/site";
+
+type FeedEntry =
+	| {
+			kind: "note";
+			date: string;
+			title: string;
+			description: string;
+			link: string;
+	  }
+	| {
+			kind: "link";
+			date: string;
+			title: string;
+			description: string;
+			link: string;
+	  };
+
+const noteTitle = (note: Note) => note.body.slice(0, 80);
+
+export const GET: APIRoute = async (context) => {
+	const [notes, links] = await Promise.all([getNotes(), getLinks()]);
+
+	const items: FeedEntry[] = [
+		...notes.map(
+			(note): FeedEntry => ({
+				kind: "note",
+				date: note.date,
+				title: noteTitle(note),
+				description: note.body,
+				link: getCanonicalUrl(note),
+			}),
+		),
+		...links.map(
+			(link): FeedEntry => ({
+				kind: "link",
+				date: link.date,
+				title: link.title,
+				description: `${link.body}\n\nExternal URL: ${link.url}`,
+				link: getCanonicalUrl(link),
+			}),
+		),
+	].sort(
+		(left, right) =>
+			new Date(right.date).getTime() - new Date(left.date).getTime(),
+	);
+
+	return rss({
+		title: `${siteMeta.name} / Notes + Links`,
+		description: "Short-form notes and annotated links from mindful.engineer.",
+		site: context.site ?? siteMeta.siteUrl,
+		items: items.map((item) => ({
+			title: item.title,
+			description: item.description,
+			pubDate: new Date(item.date),
+			link: item.link,
+		})),
+	});
+};

import { type CollectionEntry, getCollection } from "astro:content";

export interface BaseEntry {
	id: string;
	slug: string;
	date: string;
}

export interface Article extends BaseEntry {
	kind: "article";
	title: string;
	deck: string;
	summary: string;
	updated?: string;
	readMinutes: number;
	tags: string[];
	featured: boolean;
}

export interface Note extends BaseEntry {
	kind: "note";
	body: string;
}

export interface LinkEntry extends BaseEntry {
	kind: "link";
	title: string;
	source: string;
	url: string;
	summary: string;
	body: string;
	titleInferred: boolean;
}

export interface Snippet extends BaseEntry {
	kind: "snippet";
	title: string;
	language: string;
	summary: string;
	body: string;
	code: string;
}

export interface AboutPage {
	title: string;
	deck: string;
	body: string[];
	facts: Array<[string, string]>;
}

export interface NowPage {
	title: string;
	deck: string;
	updated: string;
	location: string;
	working: string;
	learning: string;
	listening: string;
	reading: Array<{ title: string; author: string }>;
	focus: string[];
}

interface LoadedContent {
	articles: Article[];
	articleSources: Map<string, CollectionEntry<"articles">>;
	notes: Note[];
	links: LinkEntry[];
	snippets: Snippet[];
	aboutPage: AboutPage;
	nowPage: NowPage;
}

export type StreamEntry = Article | Note | LinkEntry | Snippet;

export const siteMeta = {
	name: "The Mindful Engineer",
	domain: "mindful.engineer",
	siteUrl: "https://mindful.engineer",
	author: "Benjamin Kitt",
	email: "mail@mindful.engineer",
	repository: "https://github.com/benjaminkitt/mindful-engineer",
	tagline: "Moving fast. Being present.",
	description:
		"A monastery-first public reading site for articles, notes, links, snippets, and durable working notes about software and the people living inside it.",
};

export const navigation = [
	{ href: "/", label: "Index", description: "Return to the front page" },
	{ href: "/articles", label: "Articles", description: "Long-form writing" },
	{
		href: "/notes",
